import java.util.*;
import java.util.stream.Collectors;

public class Main {
    public static void main(String[] args) {
        // java.util:
        List<Integer> nums = Arrays.asList(5, 2, 8, 1, 9, 3);
        Collections.sort(nums);
        System.out.println(nums);

        // java.lang (auto-imported):
        System.out.println(Math.sqrt(144));
        System.out.println(Math.PI);
        System.out.println(String.format("%.3f", Math.E));

        // String joining:
        String result = nums.stream().map(String::valueOf).collect(Collectors.joining(", "));
        System.out.println(result);
    }
}

instruction:
`import static` lets you use a class's static members without the class name:

```java
import static java.lang.Math.*;  // now you can write sqrt(4) instead of Math.sqrt(4)
import static java.util.Collections.sort;
```

Useful for Math operations and constants in calculation-heavy code.

