import static java.lang.Math.*;
import static java.util.Arrays.asList;

public class Main {
    public static void main(String[] args) {
        // No 'Math.' prefix needed:
        double hypotenuse = sqrt(pow(3, 2) + pow(4, 2));
        System.out.println(hypotenuse);

        double circumference = 2 * PI * 5;
        System.out.printf("%.4f%n", circumference);

        // Static import of Arrays.asList:
        var numbers = asList(1, 2, 3, 4, 5);
        System.out.println(numbers);
    }
}

import java.util.Random;

public class Main {
    public static void main(String[] args) {
        Random rng = new Random(42);  // seed for reproducibility

        // nextInt(bound) — 0 to bound-1:
        for (int i = 0; i < 5; i++) {
            System.out.print(rng.nextInt(10) + " ");
        }
        System.out.println();

        // Simulate dice rolls:
        int[] counts = new int[7];
        Random dice = new Random();
        for (int i = 0; i < 6000; i++) {
            counts[dice.nextInt(6) + 1]++;
        }

        for (int face = 1; face <= 6; face++) {
            System.out.printf("Face %d: ~%d%n", face, counts[face] / 100 * 100);
        }
    }
}

import java.time.*;
import java.time.format.DateTimeFormatter;

public class Main {
    public static void main(String[] args) {
        LocalDate today = LocalDate.now();
        System.out.println(today);

        LocalDate birthday = LocalDate.of(1990, 6, 15);
        long years = ChronoUnit.YEARS.between(birthday, today);
        System.out.println("Age: " + years);

        LocalDateTime now = LocalDateTime.now();
        DateTimeFormatter fmt = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm");
        System.out.println(now.format(fmt));

        // Date arithmetic:
        LocalDate nextWeek = today.plusDays(7);
        System.out.println("Next week: " + nextWeek);
    }
}

import java.util.*;

public class Main {
    static String describe(String name) {
        Objects.requireNonNull(name, "name cannot be null");
        return "Hello, " + name;
    }

    public static void main(String[] args) {
        // null-safe toString:
        String val = null;
        System.out.println(Objects.toString(val, "(empty)"));

        // UUID for unique IDs:
        String id1 = UUID.randomUUID().toString();
        String id2 = UUID.randomUUID().toString();
        System.out.println(id1.length());
        System.out.println(id1.equals(id2));

        // requireNonNull for clean parameter checks:
        System.out.println(describe("Alex"));
        try {
            describe(null);
        } catch (NullPointerException e) {
            System.out.println("Error: " + e.getMessage());
        }
    }
}
